class Solution {
    public long mostPoints(int[][] questions) {
        int n = questions.length;
        long[] dp = new long[n];
        dp[0] = (long) questions[0][0];
        for (int i = 1; i < n; i++) {
            dp[i] = Math.max(questions[i][0] + dp[i - questions[i][1]], dp[i - 1]);
        }
        return dp[n - 1];
    }
}
